public class Rotate {
    public static void rotateLeft(int[] arr) {
        int first = arr[0];
        for (int i = 0; i < arr.length - 1; i++) {
            arr[i] = arr[i + 1];
        }
        arr[arr.length - 1] = first;
    }

    public static void main(String[] args) {
        int[] a = {10, 20, 30, 40};
        rotateLeft(a);
        for (int n : a) System.out.print(n + " ");
        System.out.println();
        rotateLeft(a);
        System.out.println(a[0]);
    }
}
